 16→var hookCmd = &cobra.Command{
 17→	Use:         "hook",
 18→	Short:       "Claude Code hook handlers (internal)",
 19→	Hidden:      true,
 20→	Annotations: map[string]string{"skipAuth": "true"},
 21→}
 22→
 23→var hookPostToolUseCmd = &cobra.Command{
 24→	Use:   "post-tool-use",
 25→	Short: "Handle post-tool-use hook events",
 26→	RunE: func(cmd *cobra.Command, args []string) error {
 27→		// No-op for now. Future: capture session context.
 28→		return nil
 29→	},
 30→}
