 46→// sessionStatus holds workspace state gathered for banner/prompt output.
 47→type sessionStatus struct {
 48→	configLoaded   bool
 49→	setupCompleted bool
 50→	connectors     map[string]config.ConnectorState
 51→	emailTotal     int
 52→	skillCount     int
 53→	skillNames     []string
 54→}
 55→
 56→func gatherStatus() *sessionStatus {
 57→	s := &sessionStatus{}
 58→
 59→	// Load config (graceful — may not exist)
 60→	cfg, err := config.Load()
 61→	if err == nil {
 62→		s.configLoaded = true
 63→		s.setupCompleted = cfg.SetupCompleted
 64→		s.connectors = cfg.Connectors
 65→	}
 66→
 67→	// Load DB stats (graceful — may not exist)
 68→	if !db.Exists() {
 69→		return s
 70→	}
 71→	d, err := db.Open()
 72→	if err != nil {
 73→		return s
 74→	}
 75→	defer d.Close()
 76→
 77→	stats, err := emails.Stats(d)
 78→	if err == nil {
 79→		s.emailTotal = stats.Total
 80→	}
 81→
 82→	skills, err := learning.ListSkills(d)
 83→	if err == nil {
 84→		s.skillCount = len(skills)
 85→		for _, sk := range skills {
 86→			s.skillNames = append(s.skillNames, sk.SkillName)
 87→		}
 88→	}
 89→
 90→	return s
 91→}
 92→
 93→// hookOutput is the JSON structure Claude Code expects from hook stdout.
 94→type hookOutput struct {
 95→	SystemMessage    string            `json:"systemMessage,omitempty"`
 96→	HookSpecificOut  *hookSpecificOut  `json:"hookSpecificOutput,omitempty"`
 97→}
 98→
 99→type hookSpecificOut struct {
100→	HookEventName     string `json:"hookEventName"`
101→	AdditionalContext string `json:"additionalContext,omitempty"`
102→}
103→
104→// runSessionStart outputs JSON with systemMessage (visible banner) and
105→// additionalContext (LLM context) for the SessionStart hook.
106→func runSessionStart() error {
107→	s := gatherStatus()
108→
109→	banner := buildBanner(s)
110→	context := buildPromptContext(s)
111→
112→	out := hookOutput{
113→		SystemMessage: banner,
114→		HookSpecificOut: &hookSpecificOut{
115→			HookEventName:     "SessionStart",
116→			AdditionalContext: context,
117→		},
118→	}
119→
120→	enc := json.NewEncoder(os.Stdout)
121→	return enc.Encode(out)
122→}
123→
124→func buildBanner(s *sessionStatus) string {
125→	var b strings.Builder
126→
127→	b.WriteString("\n\nPowered by Nurge:\n")
128→
129→	if !s.configLoaded {
130→		b.WriteString("  Run: nurge init to get started")
131→		return b.String()
132→	}
133→
134→	// Connectors
135→	hasConnectors := false
136→	for id, c := range s.connectors {
137→		if !c.Connected {
138→			continue
139→		}
140→		hasConnectors = true
141→		switch c.Type {
142→		case "email":
143→			fmt.Fprintf(&b, "  %s: %s (%s emails synced)\n", capitalize(id), c.Account, formatCount(s.emailTotal))
144→		case "crm":
145→			fmt.Fprintf(&b, "  %s: connected\n", capitalize(id))
146→		}
147→	}
148→
149→	if !hasConnectors {
150→		b.WriteString("  No connectors configured.\n")
151→		b.WriteString("  Run: nurge init --force to reconnect")
152→		return b.String()
153→	}
154→
155→	// Skills
156→	fmt.Fprintf(&b, "  Skills: %d active\n", s.skillCount)
157→
158→	if s.setupCompleted {
159→		b.WriteString("  Try:\n")
160→		b.WriteString("    \"Write a cold email to the CTO at Datastack\"\n")
161→		b.WriteString("    \"Research Acme Corp and qualify them\"\n")
162→		b.WriteString("    \"Show my pipeline\"")
163→	} else {
164→		b.WriteString("  Run /nurge:setup to get started")
165→	}
166→
167→	return b.String()
168→}
169→
170→func buildPromptContext(s *sessionStatus) string {
171→	var b strings.Builder
172→
173→	if !s.configLoaded || !s.setupCompleted {
174→		b.WriteString("You are in a Nurge workspace. Setup is not complete. ")
175→		b.WriteString("Guide the user to run /nurge:setup to finish configuration. ")
176→		b.WriteString("Do not attempt to use nurge data commands — they will have no data yet.")
177→		return b.String()
178→	}
179→
180→	b.WriteString("You are in a Nurge outbound sales workspace.\n")
181→	fmt.Fprintf(&b, "Status: Setup complete. %s emails synced. %d skills active.\n", formatCount(s.emailTotal), s.skillCount)
182→	b.WriteString("Rules:\n")
183→	b.WriteString("- Use `nurge` CLI commands for all data access. Never read .nurge/ directly.\n")
184→	b.WriteString("- For ICP and product context, run: nurge config show --format json\n")
185→	b.WriteString("- For email patterns and insights, run: nurge context generate --format json\n")
186→	b.WriteString("- For email stats, run: nurge emails stats --format json\n")
187→	b.WriteString("- When writing outbound emails, always run: nurge send")
188→
189→	if len(s.skillNames) > 0 {
190→		fmt.Fprintf(&b, "\nAvailable skills: %s", strings.Join(s.skillNames, ", "))
191→	}
192→
193→	return b.String()
194→}
195→
196→func capitalize(s string) string {
197→	if s == "" {
198→		return s
199→	}
200→	return strings.ToUpper(s[:1]) + s[1:]
201→}
202→
203→func formatCount(n int) string {
204→	if n >= 1000 {
205→		return fmt.Sprintf("%d,%03d", n/1000, n%1000)
206→	}
207→	return fmt.Sprintf("%d", n)
208→}
