  1→package init
  2→
  3→import (
  4→	"encoding/json"
  5→	"fmt"
  6→	"os"
  7→	"path/filepath"
  8→)
  9→
 10→type hooksStep struct{}
 11→
 12→func (s *hooksStep) Name() string { return "Claude Code hooks installed" }
 13→
 14→// hookEntry is a single hook command within a matcher group.
 15→type hookEntry struct {
 16→	command string
 17→}
 18→
 19→// hookGroup defines a matcher group with its hooks for a given event.
 20→type hookGroup struct {
 21→	event   string
 22→	matcher string
 23→	hooks   []hookEntry
 24→}
 25→
 26→// requiredHookGroups defines all hook groups nurge needs installed.
 27→// Hooks sharing the same event+matcher are grouped together (matching entire.io's pattern).
 28→var requiredHookGroups = []hookGroup{
 29→	{
 30→		event:   "PostToolUse",
 31→		matcher: "Bash",
 32→		hooks:   []hookEntry{{command: "nurge hook post-tool-use"}},
 33→	},
 34→	{
 35→		event:   "SessionStart",
 36→		matcher: "",
 37→		hooks:   []hookEntry{{command: "nurge hook session-start"}},
 38→	},
 39→}
 40→
 41→func (s *hooksStep) Done() (bool, error) {
 42→	data, err := os.ReadFile(claudeSettingsPath())
 43→	if err != nil {
 44→		if os.IsNotExist(err) {
 45→			return false, nil
 46→		}
 47→		return false, err
 48→	}
 49→
 50→	var settings map[string]any
 51→	if err := json.Unmarshal(data, &settings); err != nil {
 52→		return false, nil
 53→	}
 54→
 55→	hooks, ok := settings["hooks"].(map[string]any)
 56→	if !ok {
 57→		return false, nil
 58→	}
 59→
 60→	for _, g := range requiredHookGroups {
 61→		for _, h := range g.hooks {
 62→			if !hookCommandExists(hooks, g.event, h.command) {
 63→				return false, nil
 64→			}
 65→		}
 66→	}
 67→	return true, nil
 68→}
 69→
 70→func (s *hooksStep) Run() error {
 71→	settingsPath := claudeSettingsPath()
 72→
 73→	if err := os.MkdirAll(filepath.Dir(settingsPath), 0755); err != nil {
 74→		return fmt.Errorf("creating .claude/: %w", err)
 75→	}
 76→
 77→	// Load existing settings or start fresh
 78→	settings := make(map[string]any)
 79→	if data, err := os.ReadFile(settingsPath); err == nil {
 80→		json.Unmarshal(data, &settings) // ignore error, start fresh if corrupt
 81→	}
 82→
 83→	hooks, _ := settings["hooks"].(map[string]any)
 84→	if hooks == nil {
 85→		hooks = make(map[string]any)
 86→	}
 87→
 88→	for _, g := range requiredHookGroups {
 89→		// Collect commands that are missing
 90→		var missing []hookEntry
 91→		for _, h := range g.hooks {
 92→			if !hookCommandExists(hooks, g.event, h.command) {
 93→				missing = append(missing, h)
 94→			}
 95→		}
 96→		if len(missing) == 0 {
 97→			continue
 98→		}
 99→
100→		// Find existing matcher entry for this event+matcher, or create one
101→		eventHooks, _ := hooks[g.event].([]any)
102→		matcherIdx := -1
103→		for i, item := range eventHooks {
104→			m, ok := item.(map[string]any)
105→			if !ok {
106→				continue
107→			}
108→			if matcher, _ := m["matcher"].(string); matcher == g.matcher {
109→				matcherIdx = i
110→				break
111→			}
112→		}
113→
114→		if matcherIdx >= 0 {
115→			// Append to existing matcher entry
116→			entry := eventHooks[matcherIdx].(map[string]any)
117→			innerHooks, _ := entry["hooks"].([]any)
118→			for _, h := range missing {
119→				innerHooks = append(innerHooks, map[string]any{
120→					"type":    "command",
121→					"command": h.command,
122→				})
123→			}
124→			entry["hooks"] = innerHooks
125→		} else {
126→			// Create new matcher entry with all hooks
127→			var innerHooks []any
128→			for _, h := range g.hooks {
129→				innerHooks = append(innerHooks, map[string]any{
130→					"type":    "command",
131→					"command": h.command,
132→				})
133→			}
134→			entry := map[string]any{
135→				"matcher": g.matcher,
136→				"hooks":   innerHooks,
137→			}
138→			eventHooks = append(eventHooks, entry)
139→		}
140→		hooks[g.event] = eventHooks
141→	}
142→
143→	settings["hooks"] = hooks
144→
145→	// Set permissions so nurge commands and skill edits don't prompt
146→	permissions, _ := settings["permissions"].(map[string]any)
147→	if permissions == nil {
148→		permissions = make(map[string]any)
149→	}
150→	allow, _ := permissions["allow"].([]any)
151→	requiredPerms := []string{
152→		"Bash(nurge *)",
153→		"Read",
154→		"Edit(.claude/skills/**)",
155→	}
156→	for _, perm := range requiredPerms {
157→		if !containsString(allow, perm) {
158→			allow = append(allow, perm)
159→		}
160→	}
161→	permissions["allow"] = allow
162→	settings["permissions"] = permissions
163→
164→	data, err := json.MarshalIndent(settings, "", "  ")
165→	if err != nil {
166→		return fmt.Errorf("marshaling settings: %w", err)
167→	}
168→
169→	if err := os.WriteFile(settingsPath, data, 0644); err != nil {
170→		return fmt.Errorf("writing settings: %w", err)
171→	}
172→
173→	return nil
174→}
175→
176→// hookCommandExists checks if a specific command already exists under the given event key.
177→func hookCommandExists(hooks map[string]any, event, command string) bool {
178→	arr, ok := hooks[event].([]any)
179→	if !ok {
180→		return false
181→	}
182→	for _, item := range arr {
183→		m, ok := item.(map[string]any)
184→		if !ok {
185→			continue
186→		}
187→		innerHooks, ok := m["hooks"].([]any)
188→		if !ok {
189→			continue
190→		}
191→		for _, h := range innerHooks {
192→			hm, ok := h.(map[string]any)
193→			if !ok {
194→				continue
195→			}
196→			if cmd, ok := hm["command"].(string); ok && cmd == command {
197→				return true
198→			}
199→		}
200→	}
201→	return false
202→}
203→
204→func containsString(arr []any, s string) bool {
205→	for _, v := range arr {
206→		if str, ok := v.(string); ok && str == s {
207→			return true
208→		}
209→	}
210→	return false
211→}
212→
213→func claudeSettingsPath() string {
214→	return filepath.Join(".claude", "settings.json")
215→}
