 1→package cmd
 2→
 3→import (
 4→	"fmt"
 5→	"io"
 6→	"os"
 7→	"strings"
 8→
 9→	"github.com/spf13/cobra"
10→	"github.com/usenurge/nurgesh/internal/db"
11→	"github.com/usenurge/nurgesh/internal/learning"
12→)
13→
14→var learnCmd = &cobra.Command{
15→	Use:   "learn",
16→	Short: "Manage learnings from Claude Code sessions",
17→}
18→
19→var learnType string
20→var learnFormat string
21→var learnSession string
22→
23→var learnSaveCmd = &cobra.Command{
24→	Use:   "save",
25→	Short: "Save a learning from stdin",
26→	Long:  "Reads learning content from stdin and saves it to the database.",
27→	RunE: func(cmd *cobra.Command, args []string) error {
28→		if learnType == "" {
29→			return fmt.Errorf("--type is required (tone, icp, product, pattern, competitor, preference)")
30→		}
31→
32→		data, err := io.ReadAll(os.Stdin)
33→		if err != nil {
34→			return fmt.Errorf("reading stdin: %w", err)
35→		}
36→		content := strings.TrimSpace(string(data))
37→		if content == "" {
38→			return fmt.Errorf("no content provided on stdin")
39→		}
40→
41→		d, err := db.Open()
42→		if err != nil {
43→			return err
44→		}
45→		defer d.Close()
46→
47→		id, err := learning.SaveLearning(d, learnType, content, learnSession)
48→		if err != nil {
49→			return err
50→		}
51→
52→		fmt.Printf("Saved learning #%d (type: %s)\n", id, learnType)
53→		return nil
54→	},
55→}
56→
57→var learnListCmd = &cobra.Command{
58→	Use:   "list",
59→	Short: "List all learnings",
60→	RunE: func(cmd *cobra.Command, args []string) error {
61→		d, err := db.Open()
62→		if err != nil {
63→			return err
64→		}
65→		defer d.Close()
66→
67→		learnings, err := learning.ListLearnings(d, learnType)
68→		if err != nil {
69→			return err
70→		}
71→
72→		if learnFormat == "json" {
73→			return learning.PrintJSON(learnings)
74→		}
75→
76→		if len(learnings) == 0 {
77→			fmt.Println("No learnings yet.")
78→			return nil
79→		}
80→
81→		for _, l := range learnings {
82→			fmt.Printf("#%d [%s] %s\n   %s\n\n", l.ID, l.Type, l.CreatedAt, l.Content)
83→		}
84→		return nil
85→	},
86→}
87→
88→func init() {
89→	learnSaveCmd.Flags().StringVar(&learnType, "type", "", "Learning type (tone, icp, product, pattern, competitor, preference)")
90→	learnSaveCmd.Flags().StringVar(&learnSession, "session", "", "Source session identifier")
91→
92→	learnListCmd.Flags().StringVar(&learnType, "type", "", "Filter by learning type")
93→	learnListCmd.Flags().StringVar(&learnFormat, "format", "", "Output format (json)")
94→
95→	learnCmd.AddCommand(learnSaveCmd)
96→	learnCmd.AddCommand(learnListCmd)
97→	rootCmd.AddCommand(learnCmd)
98→}
