 1→package cmd
 2→
 3→import (
 4→	"fmt"
 5→	"os"
 6→
 7→	"github.com/spf13/cobra"
 8→	"github.com/usenurge/nurgesh/internal/auth"
 9→)
10→
11→var (
12→	buildVersion = "dev"
13→	buildCommit  = "none"
14→	buildDate    = "unknown"
15→)
16→
17→var convexSiteURL = ""
18→
19→// SetVersion sets the build version info from ldflags.
20→func SetVersion(version, commit, date string) {
21→	buildVersion = version
22→	buildCommit = commit
23→	buildDate = date
24→}
25→
26→// SetConvexURL sets the Convex deployment URL from ldflags.
