package init

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
)

type hooksStep struct{}

func (s *hooksStep) Name() string { return "Claude Code hooks installed" }

// hookEntry is a single hook command within a matcher group.
type hookEntry struct {
	command string
}

// hookGroup defines a matcher group with its hooks for a given event.
type hookGroup struct {
	event   string
	matcher string
	hooks   []hookEntry
}

// requiredHookGroups defines all hook groups nurge needs installed.
// Hooks sharing the same event+matcher are grouped together (matching entire.io's pattern).
var requiredHookGroups = []hookGroup{
	{
		event:   "PostToolUse",
		matcher: "Bash",
		hooks:   []hookEntry{{command: "nurge hook post-tool-use"}},
	},
	{
		event:   "SessionStart",
		matcher: "",
		hooks:   []hookEntry{{command: "nurge hook session-start"}},
	},
}

func (s *hooksStep) Done() (bool, error) {
	data, err := os.ReadFile(claudeSettingsPath())
	if err != nil {
		if os.IsNotExist(err) {
			return false, nil
		}
		return false, err
	}

	var settings map[string]any
	if err := json.Unmarshal(data, &settings); err != nil {
		return false, nil
	}

	hooks, ok := settings["hooks"].(map[string]any)
	if !ok {
		return false, nil
	}

	for _, g := range requiredHookGroups {
		for _, h := range g.hooks {
			if !hookCommandExists(hooks, g.event, h.command) {
				return false, nil
			}
		}
	}
	return true, nil
}

func (s *hooksStep) Run() error {
	settingsPath := claudeSettingsPath()

	if err := os.MkdirAll(filepath.Dir(settingsPath), 0755); err != nil {
		return fmt.Errorf("creating .claude/: %w", err)
	}

	// Load existing settings or start fresh
	settings := make(map[string]any)
	if data, err := os.ReadFile(settingsPath); err == nil {
		json.Unmarshal(data, &settings) // ignore error, start fresh if corrupt
	}

	hooks, _ := settings["hooks"].(map[string]any)
	if hooks == nil {
		hooks = make(map[string]any)
	}

	for _, g := range requiredHookGroups {
		// Collect commands that are missing
		var missing []hookEntry
		for _, h := range g.hooks {
			if !hookCommandExists(hooks, g.event, h.command) {
				missing = append(missing, h)
			}
		}
		if len(missing) == 0 {
			continue
		}

		// Find existing matcher entry for this event+matcher, or create one
		eventHooks, _ := hooks[g.event].([]any)
		matcherIdx := -1
		for i, item := range eventHooks {
			m, ok := item.(map[string]any)
			if !ok {
				continue
			}
			if matcher, _ := m["matcher"].(string); matcher == g.matcher {
				matcherIdx = i
				break
			}
		}

		if matcherIdx >= 0 {
			// Append to existing matcher entry
			entry := eventHooks[matcherIdx].(map[string]any)
			innerHooks, _ := entry["hooks"].([]any)
			for _, h := range missing {
				innerHooks = append(innerHooks, map[string]any{
					"type":    "command",
					"command": h.command,
				})
			}
			entry["hooks"] = innerHooks
		} else {
			// Create new matcher entry with all hooks
			var innerHooks []any
			for _, h := range g.hooks {
				innerHooks = append(innerHooks, map[string]any{
					"type":    "command",
					"command": h.command,
				})
			}
			entry := map[string]any{
				"matcher": g.matcher,
				"hooks":   innerHooks,
			}
			eventHooks = append(eventHooks, entry)
		}
		hooks[g.event] = eventHooks
	}

	settings["hooks"] = hooks

	// Set permissions so nurge commands and skill edits don't prompt
	permissions, _ := settings["permissions"].(map[string]any)
	if permissions == nil {
		permissions = make(map[string]any)
	}
	allow, _ := permissions["allow"].([]any)
	requiredPerms := []string{
		"Bash(nurge *)",
		"Read",
		"Edit(.claude/skills/**)",
	}
	for _, perm := range requiredPerms {
		if !containsString(allow, perm) {
			allow = append(allow, perm)
		}
	}
	permissions["allow"] = allow
	settings["permissions"] = permissions

	data, err := json.MarshalIndent(settings, "", "  ")
	if err != nil {
		return fmt.Errorf("marshaling settings: %w", err)
	}

	if err := os.WriteFile(settingsPath, data, 0644); err != nil {
		return fmt.Errorf("writing settings: %w", err)
	}

	return nil
}

// hookCommandExists checks if a specific command already exists under the given event key.
func hookCommandExists(hooks map[string]any, event, command string) bool {
	arr, ok := hooks[event].([]any)
	if !ok {
		return false
	}
	for _, item := range arr {
		m, ok := item.(map[string]any)
		if !ok {
			continue
		}
		innerHooks, ok := m["hooks"].([]any)
		if !ok {
			continue
		}
		for _, h := range innerHooks {
			hm, ok := h.(map[string]any)
			if !ok {
				continue
			}
			if cmd, ok := hm["command"].(string); ok && cmd == command {
				return true
			}
		}
	}
	return false
}

func containsString(arr []any, s string) bool {
	for _, v := range arr {
		if str, ok := v.(string); ok && str == s {
			return true
		}
	}
	return false
}

func claudeSettingsPath() string {
	return filepath.Join(".claude", "settings.json")
}

package db

import (
	"database/sql"
	"fmt"
	"os"

	_ "modernc.org/sqlite"
)

const dbPath = ".nurge/nurge.db"
const dsn = "file:.nurge/nurge.db?_pragma=busy_timeout(5000)&_pragma=journal_mode(WAL)&_pragma=foreign_keys(1)"

// Exists checks if the database file exists.
func Exists() bool {
	_, err := os.Stat(dbPath)
	return err == nil
}

// Open returns a connection to the nurge database.
func Open() (*sql.DB, error) {
	db, err := sql.Open("sqlite", dsn)
	if err != nil {
		return nil, fmt.Errorf("opening database: %w", err)
	}
	db.SetMaxOpenConns(1) // SQLite doesn't handle concurrent writes well
	return db, nil
}

// Create creates the database and runs the schema.
func Create() error {
	db, err := Open()
	if err != nil {
		return err
	}
	defer db.Close()

	_, err = db.Exec(Schema)
	if err != nil {
		return fmt.Errorf("creating schema: %w", err)
	}
	return nil
}

const Schema = `
-- Connector registry
CREATE TABLE IF NOT EXISTS connectors (
    id TEXT PRIMARY KEY,
    type TEXT NOT NULL,
    account TEXT DEFAULT '',
    connected_at TEXT,
    last_sync_at TEXT,
    total_synced INTEGER DEFAULT 0,
    sync_cursor TEXT DEFAULT '',
    status TEXT DEFAULT 'connected'
);

-- Email store (from Gmail)
CREATE TABLE IF NOT EXISTS emails (
    id TEXT PRIMARY KEY,
    source TEXT NOT NULL DEFAULT 'gmail',
    thread_id TEXT NOT NULL,
    subject TEXT,
    from_email TEXT NOT NULL,
    to_emails TEXT NOT NULL,
    cc_emails TEXT DEFAULT '[]',
    date TEXT NOT NULL,
    snippet TEXT,
    body_preview TEXT,
    labels TEXT DEFAULT '[]',
    class TEXT DEFAULT 'unclassified',
    class_confidence REAL DEFAULT 0,
    classified_by TEXT DEFAULT '',
    created_at TEXT DEFAULT (datetime('now')),
    synced_at TEXT DEFAULT (datetime('now'))
);

-- Contacts (from Gmail sent-to addresses + HubSpot if connected)
CREATE TABLE IF NOT EXISTS contacts (
    id TEXT PRIMARY KEY,
    source TEXT NOT NULL,
    source_id TEXT DEFAULT '',
    email TEXT NOT NULL,
    name TEXT DEFAULT '',
    domain TEXT DEFAULT '',
    company TEXT DEFAULT '',
    title TEXT DEFAULT '',
    phone TEXT DEFAULT '',
    lead_status TEXT DEFAULT '',
    owner TEXT DEFAULT '',
    last_activity_at TEXT,
    email_count INTEGER DEFAULT 0,
    last_emailed_at TEXT,
    class TEXT DEFAULT 'unknown',
    created_at TEXT DEFAULT (datetime('now')),
    updated_at TEXT DEFAULT (datetime('now')),
    UNIQUE(source, email)
);

-- Deals (from HubSpot — empty without CRM)
CREATE TABLE IF NOT EXISTS deals (
    id TEXT PRIMARY KEY,
    source TEXT NOT NULL DEFAULT 'hubspot',
    source_id TEXT NOT NULL,
    name TEXT NOT NULL,
    contact_email TEXT DEFAULT '',
    company TEXT DEFAULT '',
    stage TEXT DEFAULT '',
    status TEXT DEFAULT 'open',
    value REAL DEFAULT 0,
    currency TEXT DEFAULT 'USD',
    close_date TEXT,
    owner TEXT DEFAULT '',
    created_at TEXT DEFAULT (datetime('now')),
    synced_at TEXT DEFAULT (datetime('now'))
);

CREATE INDEX IF NOT EXISTS idx_emails_class ON emails(class);
CREATE INDEX IF NOT EXISTS idx_emails_date ON emails(date);
CREATE INDEX IF NOT EXISTS idx_emails_source ON emails(source);
CREATE INDEX IF NOT EXISTS idx_contacts_source ON contacts(source);
CREATE INDEX IF NOT EXISTS idx_contacts_email ON contacts(email);
CREATE INDEX IF NOT EXISTS idx_contacts_domain ON contacts(domain);
CREATE INDEX IF NOT EXISTS idx_deals_contact ON deals(contact_email);
CREATE INDEX IF NOT EXISTS idx_deals_stage ON deals(stage);

-- Learnings captured from Claude Code sessions
CREATE TABLE IF NOT EXISTS learnings (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
