package init

import (
	"fmt"
	"os"
)

// Options holds CLI flags for nurge init.
type Options struct {
	Credentials    string
	SkipConnectors bool
	SkipHooks      bool
	Force          bool
	Verbose        bool
}

// Step is the interface each init step implements.
type Step interface {
	Name() string
	Done() (bool, error)
	Run() error
}

// Run executes all init steps in order.
func Run(opts Options) error {
	fmt.Println()
	fmt.Println("  nurge — outbound that learns")
	fmt.Println()

	steps := buildSteps(opts)

	for _, s := range steps {
		if !opts.Force {
			done, err := s.Done()
			if err != nil {
				printFail(s.Name(), err)
				return err
			}
			if done {
				printSkip(s.Name())
				continue
			}
		}

		if err := s.Run(); err != nil {
			printFail(s.Name(), err)
			return err
		}
		printDone(s.Name())
	}

	return nil
}

func buildSteps(opts Options) []Step {
	var steps []Step

	steps = append(steps, &projectStep{})
	steps = append(steps, &databaseStep{})
	steps = append(steps, &gitignoreStep{})

	if !opts.SkipConnectors {
		steps = append(steps, &connectStep{credentials: opts.Credentials})
	}

	if !opts.SkipHooks {
		steps = append(steps, &hooksStep{})
	}

	steps = append(steps, &skillStep{})
	steps = append(steps, &gitStep{})
	steps = append(steps, &nextStepStep{})

	return steps
}

func printDone(name string) {
	fmt.Fprintf(os.Stdout, "  \033[32m✓\033[0m %s\n", name)
}

func printSkip(name string) {
	fmt.Fprintf(os.Stdout, "  \033[32m✓\033[0m %s (already done)\n", name)
}

func printFail(name string, err error) {
	fmt.Fprintf(os.Stderr, "  \033[31m✗\033[0m %s: %v\n", name, err)
}

package init

import (
	"fmt"
	"os"
	"os/exec"
	"syscall"
)

type nextStepStep struct{}

func (s *nextStepStep) Name() string { return "" } // no label, just prints

func (s *nextStepStep) Done() (bool, error) { return false, nil }

func (s *nextStepStep) Run() error {
	fmt.Println()

	if isInsideClaudeCode() {
		fmt.Println("  You're ready. Run:")
		fmt.Println("    /nurge:setup")
		fmt.Println()
		return nil
	}

	if isClaudeInstalled() {
		fmt.Println("  Launching Claude Code...")
		fmt.Println()
		return launchClaude()
	}

	fmt.Println("  Almost there! Install Claude Code first:")
	fmt.Println("    https://claude.ai/code")
	fmt.Println()
	fmt.Println("  Then run:")
	fmt.Println("    claude -p \"/nurge:setup\"")
	fmt.Println()
	return nil
}

func isInsideClaudeCode() bool {
	return os.Getenv("CLAUDE_CODE") != ""
}

func isClaudeInstalled() bool {
	_, err := exec.LookPath("claude")
	return err == nil
}

// launchClaude replaces the current process with claude in interactive mode.
// SessionStart hooks handle the rest — banner shows status, prompt guides Claude.
func launchClaude() error {
	claudePath, err := exec.LookPath("claude")
	if err != nil {
		return fmt.Errorf("claude not found: %w", err)
	}

	// syscall.Exec replaces the nurge process with claude — clean handoff
	return syscall.Exec(claudePath, []string{"claude"}, os.Environ())
}

