package init

import (
	"fmt"
	"os"

	"github.com/usenurge/nurgesh/internal/config"
)

const nurgeDir = ".nurge"

type projectStep struct{}

func (s *projectStep) Name() string { return "Project created" }

func (s *projectStep) Done() (bool, error) {
	info, err := os.Stat(nurgeDir)
	if err != nil {
		if os.IsNotExist(err) {
			return false, nil
		}
		return false, err
	}
	if !info.IsDir() {
		return false, fmt.Errorf(".nurge exists but is not a directory")
	}
	// Check config.json exists too
	if _, err := os.Stat(config.Path()); err == nil {
		return true, nil
	}
	return false, nil
}

func (s *projectStep) Run() error {
	// Create .nurge/ directory
	if err := os.MkdirAll(nurgeDir, 0755); err != nil {
		return fmt.Errorf("creating .nurge/: %w", err)
	}

	// Create connectors subdirectory
	if err := os.MkdirAll(nurgeDir+"/connectors", 0755); err != nil {
		return fmt.Errorf("creating connectors dir: %w", err)
	}

	// Write initial config
	cfg := config.Default()
	if err := config.Write(cfg); err != nil {
		return fmt.Errorf("writing config: %w", err)
	}

	return nil
}

