// HookInput is the generic structure for all hook stdin payloads.
// Claude Code sends JSON on stdin to hooks. Fields vary by event type.
type HookInput struct {
	SessionID      string `json:"session_id"`
	Model          string `json:"model,omitempty"`
	Source         string `json:"source,omitempty"`
	TranscriptPath string `json:"transcript_path,omitempty"`

	// UserPromptSubmit fields
	Prompt string `json:"prompt,omitempty"`

	// Stop fields
	StopReason    string   `json:"stop_reason,omitempty"`
	ModifiedFiles []string `json:"modified_files,omitempty"`
}

// ReadStdin reads and parses hook JSON from stdin.
func ReadStdin() (*HookInput, error) {
	data, err := io.ReadAll(os.Stdin)
	if err != nil {
		return nil, fmt.Errorf("reading stdin: %w", err)
	}
	if len(data) == 0 {
		return &HookInput{}, nil
	}

	var input HookInput
	if err := json.Unmarshal(data, &input); err != nil {
		return nil, fmt.Errorf("parsing hook input: %w", err)
	}
	return &input, nil
}

