package sessions

import (
	"bufio"
	"log/slog"
	"os"
	"path/filepath"
	"sync"
)

const (
	logDir  = ".nurge/sessions"
	logFile = ".nurge/sessions/nurge.log"
	bufSize = 8192 // 8KB buffer
)

var (
	loggerOnce sync.Once
	logger     *slog.Logger
	logWriter  *bufio.Writer
	logFD      *os.File
)

// Logger returns a shared slog.Logger that writes JSON to .nurge/sessions/nurge.log.
// Safe to call from hooks — creates the file and directory if needed.
// Returns a no-op logger if the file cannot be opened.
func Logger() *slog.Logger {
	loggerOnce.Do(func() {
		if err := os.MkdirAll(logDir, 0755); err != nil {
			logger = slog.New(slog.NewJSONHandler(os.Stderr, nil))
			return
		}

		f, err := os.OpenFile(logFile, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0644)
		if err != nil {
			logger = slog.New(slog.NewJSONHandler(os.Stderr, nil))
			return
		}

		logFD = f
		logWriter = bufio.NewWriterSize(f, bufSize)
		logger = slog.New(slog.NewJSONHandler(logWriter, &slog.HandlerOptions{
			Level: slog.LevelInfo,
		}))
	})
	return logger
}

// FlushLog flushes the buffered log writer. Call before process exit.
func FlushLog() {
	if logWriter != nil {
		logWriter.Flush()
	}
}

// TmpDir returns the path to the sessions temp directory.
func TmpDir() string {
	return filepath.Join(logDir, "tmp")
}

