	"encoding/json"
	"fmt"
)

// CreateSession inserts a new session row with status=active.
func CreateSession(db *sql.DB, id, model, source, transcriptPath string) error {
	_, err := db.Exec(
		`INSERT OR IGNORE INTO sessions (id, model, source, transcript_path, status) VALUES (?, ?, ?, ?, 'active')`,
		id, model, source, transcriptPath,
	)
	if err != nil {
		return fmt.Errorf("creating session: %w", err)
	}
	return nil
}

// AddEvent inserts a session_events row.
func AddEvent(db *sql.DB, sessionID, eventType string, payload any) error {
	payloadJSON, err := json.Marshal(payload)
	if err != nil {
		payloadJSON = []byte("{}")
	}
	_, err = db.Exec(
		`INSERT INTO session_events (session_id, type, payload) VALUES (?, ?, ?)`,
		sessionID, eventType, string(payloadJSON),
	)
	if err != nil {
		return fmt.Errorf("adding event: %w", err)
	}
	return nil
}

// AddCheckpoint inserts a session_checkpoints row with modified files.
func AddCheckpoint(db *sql.DB, sessionID string, modifiedFiles []string) error {
	filesJSON, err := json.Marshal(modifiedFiles)
	if err != nil {
		filesJSON = []byte("[]")
	}
	_, err = db.Exec(
		`INSERT INTO session_checkpoints (session_id, modified_files) VALUES (?, ?)`,
		sessionID, string(filesJSON),
	)
	if err != nil {
		return fmt.Errorf("adding checkpoint: %w", err)
	}
	return nil
}

// EndSession updates a session's status to ended and sets ended_at.
func EndSession(db *sql.DB, sessionID string) error {
	_, err := db.Exec(
		`UPDATE sessions SET status = 'ended', ended_at = datetime('now') WHERE id = ?`,
		sessionID,
	)
	if err != nil {
		return fmt.Errorf("ending session: %w", err)
	}
	return nil
}

