package sessions

import (
	"database/sql"
	"fmt"
	"strings"
)

// SaveDraft stores an AI-generated draft linked to a session.
func SaveDraft(db *sql.DB, sessionID, aiDraft, contentType string) (int64, error) {
	if contentType == "" {
		contentType = "email"
	}
	res, err := db.Exec(
		`INSERT INTO content_drafts (session_id, ai_draft, content_type) VALUES (?, ?, ?)`,
		sessionID, aiDraft, contentType,
	)
	if err != nil {
		return 0, fmt.Errorf("saving draft: %w", err)
	}
	return res.LastInsertId()
}

// SaveFinal stores the user's final version and computes the diff.
func SaveFinal(db *sql.DB, draftID int64, userFinal string) error {
	// Get the original draft
	var aiDraft string
	err := db.QueryRow(`SELECT ai_draft FROM content_drafts WHERE id = ?`, draftID).Scan(&aiDraft)
	if err != nil {
		return fmt.Errorf("loading draft: %w", err)
	}

	diff := computeDiff(aiDraft, userFinal)
	_, err = db.Exec(
		`UPDATE content_drafts SET user_final = ?, diff = ? WHERE id = ?`,
		userFinal, diff, draftID,
	)
	if err != nil {
		return fmt.Errorf("saving final: %w", err)
	}
	return nil
}

// computeDiff produces a simple line-level diff summary.
// Not a full unified diff — just enough to see what changed.
func computeDiff(draft, final string) string {
	if draft == final {
		return "no changes"
	}

	draftLines := strings.Split(draft, "\n")
	finalLines := strings.Split(final, "\n")

	var changes []string

	// Simple comparison: report added/removed/changed line counts
	added, removed, changed := 0, 0, 0
	maxLen := len(draftLines)
	if len(finalLines) > maxLen {
		maxLen = len(finalLines)
	}

	for i := 0; i < maxLen; i++ {
		var dLine, fLine string
		if i < len(draftLines) {
			dLine = draftLines[i]
		}
		if i < len(finalLines) {
			fLine = finalLines[i]
		}

		if dLine == "" && fLine != "" {
			added++
		} else if dLine != "" && fLine == "" {
			removed++
		} else if dLine != fLine {
			changed++
		}
	}

	if added > 0 {
		changes = append(changes, fmt.Sprintf("+%d lines", added))
	}
	if removed > 0 {
		changes = append(changes, fmt.Sprintf("-%d lines", removed))
	}
	if changed > 0 {
		changes = append(changes, fmt.Sprintf("~%d lines changed", changed))
	}

	if len(changes) == 0 {
		return "no changes"
	}
	return strings.Join(changes, ", ")
}

