	db.EnsureSessionTables(d)
	sessions.AddEvent(d, input.SessionID, "stop", input)
	if len(input.ModifiedFiles) > 0 {
		sessions.AddCheckpoint(d, input.SessionID, input.ModifiedFiles)
	}

	sessions.Logger().Info("stop", "session_id", input.SessionID, "reason", input.StopReason)
	sessions.FlushLog()
	return nil
}

// runSessionEnd marks a session as ended.
func runSessionEnd() error {
	input, err := sessions.ReadStdin()
	if err != nil || input == nil || input.SessionID == "" {
		return nil
	}

	if !db.Exists() {
		return nil
	}
	d, err := db.Open()
	if err != nil {
		return nil
	}
	defer d.Close()

	db.EnsureSessionTables(d)
	sessions.EndSession(d, input.SessionID)
	sessions.AddEvent(d, input.SessionID, "session_end", input)

	sessions.Logger().Info("session-end", "session_id", input.SessionID)
	sessions.FlushLog()
	return nil
}

