	},
}

func init() {
	hookCmd.AddCommand(hookPostToolUseCmd)
	hookCmd.AddCommand(hookSessionStartCmd)
	hookCmd.AddCommand(hookUserPromptCmd)
	hookCmd.AddCommand(hookStopCmd)
	hookCmd.AddCommand(hookSessionEndCmd)
	rootCmd.AddCommand(hookCmd)
}

// sessionStatus holds workspace state gathered for banner/prompt output.
type sessionStatus struct {
	configLoaded   bool
	setupCompleted bool
	connectors     map[string]config.ConnectorState
	emailTotal     int
	skillCount     int
	skillNames     []string
}

func gatherStatus() *sessionStatus {
	s := &sessionStatus{}

	// Load config (graceful — may not exist)
	cfg, err := config.Load()
	if err == nil {
		s.configLoaded = true
		s.setupCompleted = cfg.SetupCompleted
		s.connectors = cfg.Connectors
	}

	// Load DB stats (graceful — may not exist)
	if !db.Exists() {
		return s
	}
	d, err := db.Open()
	if err != nil {
		return s
	}
	defer d.Close()

	stats, err := emails.Stats(d)
	if err == nil {
		s.emailTotal = stats.Total
	}

	skills, err := learning.ListSkills(d)
	if err == nil {
		s.skillCount = len(skills)
		for _, sk := range skills {
			s.skillNames = append(s.skillNames, sk.SkillName)
		}
	}

	return s
}

// hookOutput is the JSON structure Claude Code expects from hook stdout.
type hookOutput struct {
	SystemMessage    string            `json:"systemMessage,omitempty"`
	HookSpecificOut  *hookSpecificOut  `json:"hookSpecificOutput,omitempty"`
}

type hookSpecificOut struct {
	HookEventName     string `json:"hookEventName"`
	AdditionalContext string `json:"additionalContext,omitempty"`
}

// runSessionStart outputs JSON with systemMessage (visible banner) and
// additionalContext (LLM context) for the SessionStart hook.
func runSessionStart() error {
	s := gatherStatus()

	banner := buildBanner(s)
	context := buildPromptContext(s)

	out := hookOutput{
		SystemMessage: banner,
		HookSpecificOut: &hookSpecificOut{
			HookEventName:     "SessionStart",
			AdditionalContext: context,
		},
	}

	enc := json.NewEncoder(os.Stdout)
	return enc.Encode(out)
}

func buildBanner(s *sessionStatus) string {
	var b strings.Builder

	b.WriteString("\n\nPowered by Nurge:\n")

	if !s.configLoaded {
		b.WriteString("  Run: nurge init to get started")
		return b.String()
	}

	// Connectors
	hasConnectors := false
	for id, c := range s.connectors {
		if !c.Connected {
			continue
		}
		hasConnectors = true
		switch c.Type {
		case "email":
			fmt.Fprintf(&b, "  %s: %s (%s emails synced)\n", capitalize(id), c.Account, formatCount(s.emailTotal))
		case "crm":
			fmt.Fprintf(&b, "  %s: connected\n", capitalize(id))
		}
	}

	if !hasConnectors {
		b.WriteString("  No connectors configured.\n")
		b.WriteString("  Run: nurge init --force to reconnect")
		return b.String()
	}

	// Skills
	fmt.Fprintf(&b, "  Skills: %d active\n", s.skillCount)

	if s.setupCompleted {
		b.WriteString("  Try:\n")
		b.WriteString("    \"Write a cold email to the CTO at Datastack\"\n")
		b.WriteString("    \"Research Acme Corp and qualify them\"\n")
		b.WriteString("    \"Show my pipeline\"")
	} else {
		b.WriteString("  Run /nurge:setup to get started")
	}

	return b.String()
}

func buildPromptContext(s *sessionStatus) string {
	var b strings.Builder

	if !s.configLoaded || !s.setupCompleted {
		b.WriteString("You are in a Nurge workspace. Setup is not complete. ")
		b.WriteString("Guide the user to run /nurge:setup to finish configuration. ")
		b.WriteString("Do not attempt to use nurge data commands — they will have no data yet.")
		return b.String()
	}

	b.WriteString("You are in a Nurge outbound sales workspace.\n")
	fmt.Fprintf(&b, "Status: Setup complete. %s emails synced. %d skills active.\n", formatCount(s.emailTotal), s.skillCount)
	b.WriteString("Rules:\n")
	b.WriteString("- Use `nurge` CLI commands for all data access. Never read .nurge/ directly.\n")
	b.WriteString("- For ICP and product context, run: nurge config show --format json\n")
	b.WriteString("- For email patterns and insights, run: nurge context generate --format json\n")
	b.WriteString("- For email stats, run: nurge emails stats --format json\n")
	b.WriteString("- When writing outbound emails, always run: nurge send")

	if len(s.skillNames) > 0 {
		fmt.Fprintf(&b, "\nAvailable skills: %s", strings.Join(s.skillNames, ", "))
	}

	return b.String()
}

func capitalize(s string) string {
	if s == "" {
		return s
	}
	return strings.ToUpper(s[:1]) + s[1:]
}

func formatCount(n int) string {
	if n >= 1000 {
		return fmt.Sprintf("%d,%03d", n/1000, n%1000)
	}
	return fmt.Sprintf("%d", n)
}

